document.addEventListener("DOMContentLoaded",function(){const t=document.querySelectorAll(".tab-btn"),e=document.querySelectorAll(".tab-pane");t.forEach(a=>{a.addEventListener("click",()=>{const c=a.getAttribute("data-target");t.forEach(t=>t.classList.remove("active")),a.classList.add("active"),e.forEach(t=>{t.id===c?t.classList.add("active"):t.classList.remove("active")})})})});